#include <stdio.h>
int maxProfit(int* prices, int n, int k) {
    int buy[n], sell[n];
    for (int i = 0; i < n; i++) {
        buy[i] = -prices[i];
        sell[i] = 0;
    }
    for (int i = 1; i < n; i++) {
        for (int j = 0; j <= k; j++) {
            if (j > 0) {
                buy[i] = (buy[i] > sell[i-1] - prices[i]) ? buy[i] : sell[i-1] - prices[i];
            }
            sell[i] = (sell[i] > buy[i-1] + prices[i]) ? sell[i] : buy[i-1] + prices[i];
        }
    }
    return sell[n-1];
}
int main() {
    int n, k;
    scanf("%d %d", &n, &k);
    int prices[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &prices[i]);
    }
    printf("%d\n", maxProfit(prices, n, k));
    return 0;
}

