public class Main {
    public static int maxProfit(int[] prices, int n, int k) {
        int[] buy = new int[n];
        int[] sell = new int[n];
        for (int i = 0; i < n; i++) {
            buy[i] = -prices[i];
            sell[i] = 0;
        }
        for (int i = 1; i < n; i++) {
            for (int j = 0; j <= k; j++) {
                if (j > 0) {
                    buy[i] = Math.max(buy[i], sell[i-1] - prices[i]);
                }
                sell[i] = Math.max(sell[i], buy[i-1] + prices[i]);
            }
        }
        return sell[n-1];
    }
    public static void main(String[] args) {
        java.util.Scanner sc = new java.util.Scanner(System.in);
        int n = sc.nextInt();
        int k = sc.nextInt();
        int[] prices = new int[n];
        for (int i = 0; i < n; i++) {
            prices[i] = sc.nextInt();
        }
        System.out.println(maxProfit(prices, n, k));
    }
}

